using UnityEngine;

/// <summary>
/// Uso do item equipado (P7 — entry-point simples; a UI completa de
/// inventário fica para mais tarde). Ligar ao evento UseItemHold do
/// PlayerInputRouter (ou chamar UseEquippedItem por outro sistema).
///
/// Tarefa "Itens Consumíveis": o comportamento ao usar é definido por
/// <see cref="ItemData.effectType"/>:
///
/// - <see cref="ConsumableEffectType.Aderencia"/> (Raiz de Aderência) e o
///   legado "selfBuff" → buff directo no player via
///   PlayerCombat.ApplyTemporaryGripBuff.
/// - <see cref="ConsumableEffectType.Sono"/> (Flor do Silêncio),
///   <see cref="ConsumableEffectType.Resina"/> (Resina Antiga) e
///   <see cref="ConsumableEffectType.Congelamento"/> (Cristal de Gelo) →
///   efeito em área sobre EnemyStatusEffectReceiver, usando
///   item.effectRadius/affectAllInRadius (ou os valores por defeito
///   useRadius/affectAllInRadius deste componente, se o item não definir raio).
/// - <see cref="ConsumableEffectType.Invisibilidade"/> (Pó Dourado) → ambos:
///   invisibilidade do player (PlayerConsumableEffects) E "perde-alvo" em
///   inimigos próximos já em perseguição.
/// - Restantes tipos (Escudo, Velocidade, DestacarColecionaveis,
///   Regeneracao, ImunidadeCorrente, ImpulsoVertical) → efeito directo no
///   player via PlayerConsumableEffects.
/// - <see cref="ConsumableEffectType.Nenhum"/> (legado, sem selfBuff) →
///   comportamento antigo (procura de inimigo único/área com useRadius).
///
/// Em todos os casos, se o item for consumível e o uso teve efeito, remove 1
/// do inventário (e desequipa, se a quantidade chegar a 0).
/// </summary>
public class PlayerItemUser : MonoBehaviour
{
    [Header("Itens")]
    [Tooltip("Itens usáveis conhecidos (para resolver equippedItemId → ItemData). Substituível por uma base de dados de itens no futuro.")]
    public ItemData[] knownItems;

    [Header("Alcance (valores por defeito — usados se o item não definir 'effectRadius')")]
    [Tooltip("Raio à volta do player onde o item afecta inimigos.")]
    public float useRadius = 3f;

    [Tooltip("Afecta todos os inimigos no raio (ex: pó lançado ao ar). Desligado = só o mais próximo. Usado apenas por itens sem 'effectType' (legado).")]
    public bool affectAllInRadius = false;

    [Header("Input (opcional, auto-detectado)")]
    [SerializeField] private PlayerInputRouter input;

    private PlayerCombat combat;
    private PlayerConsumableEffects consumableEffects;

    private void Awake()
    {
        if (input == null) input = GetComponent<PlayerInputRouter>();
        combat = GetComponent<PlayerCombat>();
        consumableEffects = GetComponent<PlayerConsumableEffects>();
    }

    private void OnEnable()
    {
        if (input != null) input.UseItemHold += UseEquippedItem;
    }

    private void OnDisable()
    {
        if (input != null) input.UseItemHold -= UseEquippedItem;
    }

    /// <summary>Usa o item equipado. Devolve true se teve algum efeito (e, portanto, foi consumido se "consumable").</summary>
    public bool UseEquippedItem()
    {
        if (ChallengeManager.Instance != null && ChallengeManager.Instance.IsItemUsageRestricted()) return false;

        var progress = PlayerProgress.Instance;
        if (progress == null || string.IsNullOrEmpty(progress.equippedItemId)) return false;

        var item = FindItem(progress.equippedItemId);
        if (item == null || !item.usableByPlayer) return false;
        if (!progress.HasItem(item)) return false;

        bool used = ApplyItemEffect(item);

        if (used && item.consumable)
        {
            progress.RemoveItem(item, 1);

            if (progress.GetItemQuantity(item) <= 0 && progress.HasItemEquipped(item))
                progress.EquipItem(null);
        }

        return used;
    }

    /// <summary>
    /// Aplica o efeito de "item" de acordo com <see cref="ItemData.effectType"/>,
    /// sem verificar posse/equipamento nem consumir inventário (extraído de
    /// <see cref="UseEquippedItem"/> para reutilização pelo botão "Testar Efeito"
    /// do ItemDataEditor — ver <see cref="ApplyItemEffect"/> público abaixo).
    /// </summary>
    public bool ApplyItemEffect(ItemData item)
    {
        if (item == null) return false;

        switch (item.effectType)
        {
            case ConsumableEffectType.Aderencia:
                return UseSelfBuffItem(item);

            case ConsumableEffectType.Sono:
            case ConsumableEffectType.Resina:
            case ConsumableEffectType.Congelamento:
                return UseAreaEnemyItem(item);

            case ConsumableEffectType.Invisibilidade:
                return UseInvisibilityItem(item);

            case ConsumableEffectType.Escudo:
            case ConsumableEffectType.Velocidade:
            case ConsumableEffectType.DestacarColecionaveis:
            case ConsumableEffectType.Regeneracao:
            case ConsumableEffectType.ImunidadeCorrente:
            case ConsumableEffectType.ImpulsoVertical:
                return UsePlayerEffectItem(item);

            case ConsumableEffectType.CuraInstantanea:
                return UseInstantHealItem(item);

            default:
                // Legado (Tarefa #28): selfBuff ou procura de inimigo único/área.
                return item.selfBuff ? UseSelfBuffItem(item) : UseAreaEnemyItem(item);
        }
    }

    /// <summary>
    /// Broto de Vida (inventário — comprado em loja): cura instantânea de
    /// <see cref="ItemData.instantHealAmount"/> corações. O drop de chão
    /// <see cref="BrotoDeVidaPickup"/> cura directamente ao apanhar, sem passar
    /// pelo inventário nem por este método.
    /// Devolve false se o player já tiver a vida cheia (não consome o item).
    /// </summary>
    private bool UseInstantHealItem(ItemData item)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) return false;
        if (progress.currentHearts >= progress.maxHearts) return false;

        progress.Heal(item.instantHealAmount);
        return true;
    }

    /// <summary>Raiz de Aderência (e legado "selfBuff"): buff directo no player, sem procurar inimigos.</summary>
    private bool UseSelfBuffItem(ItemData item)
    {
        if (combat == null) return false;

        combat.ApplyTemporaryGripBuff(item.selfBuffKnockbackMultiplier, item.selfBuffSkidGripMultiplier, item.selfBuffDuration);
        return true;
    }

    /// <summary>Efeito directo no player (Escudo, Velocidade, Luz de Gaia, Néctar Verde, Bolha de Coral, Incenso do Vento).</summary>
    private bool UsePlayerEffectItem(ItemData item)
    {
        return consumableEffects != null && consumableEffects.ApplyEffect(item);
    }

    /// <summary>Pó Dourado: invisibilidade do player + "perde-alvo" em inimigos próximos já em perseguição.</summary>
    private bool UseInvisibilityItem(ItemData item)
    {
        bool playerEffect = consumableEffects != null && consumableEffects.ApplyEffect(item);
        bool affectedEnemies = ApplyAreaEffectOnEnemies(item);
        return playerEffect || affectedEnemies;
    }

    /// <summary>Sono (Flor do Silêncio), Resina (Resina Antiga), Congelamento (Cristal de Gelo): efeito em área sobre inimigos.</summary>
    private bool UseAreaEnemyItem(ItemData item)
    {
        return ApplyAreaEffectOnEnemies(item);
    }

    /// <summary>
    /// Procura EnemyStatusEffectReceiver no raio (item.effectRadius, ou
    /// useRadius se &lt;= 0) e aplica ApplyItem. "affectAll" segue
    /// item.affectAllInRadius para itens com effectType definido, ou
    /// affectAllInRadius (campo deste componente) para itens legados (effectType == Nenhum).
    /// </summary>
    private bool ApplyAreaEffectOnEnemies(ItemData item)
    {
        float radius = item.effectRadius > 0f ? item.effectRadius : useRadius;
        bool affectAll = item.effectType != ConsumableEffectType.Nenhum ? item.affectAllInRadius : affectAllInRadius;

        bool affectedAny = false;
        float bestDist = float.MaxValue;
        EnemyStatusEffectReceiver closest = null;

        foreach (var hit in Physics2D.OverlapCircleAll(transform.position, radius))
        {
            var receiver = hit.GetComponent<EnemyStatusEffectReceiver>();
            if (receiver == null) continue;

            if (affectAll)
            {
                if (receiver.ApplyItem(item, transform.position)) affectedAny = true;
            }
            else
            {
                float dist = ((Vector2)hit.transform.position - (Vector2)transform.position).sqrMagnitude;
                if (dist < bestDist)
                {
                    bestDist = dist;
                    closest = receiver;
                }
            }
        }

        if (!affectAll && closest != null)
            affectedAny = closest.ApplyItem(item, transform.position);

        return affectedAny;
    }

    private ItemData FindItem(string itemId)
    {
        if (knownItems == null) return null;

        foreach (var item in knownItems)
            if (item != null && item.itemId == itemId) return item;

        return null;
    }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = new Color(0.8f, 1f, 0.4f, 0.5f);
        Gizmos.DrawWireSphere(transform.position, useRadius);
    }
}
